from math import *
_call_count = 0

def generate_input(n):
    global _call_count
    _call_count += 1
    if _call_count == 1:
        a = max(1, int(n))
        vm = max(1, int(n))
        return f"{a} {vm}"
    else:
        l = max(0, int(2 * n))
        d = max(0, int(n // 2))
        vd = max(1, int(n // 3))
        return f"{l} {d} {vd}"

n = 10

a, vm = map(int, generate_input(n).split())
